export default class CustomCommand {
  async apply(cli) {
    const customCommand = await cli.makeCommand({
      rawName: "custom-command",
      name: "custom-command",
      alias: "cc",
      usage: "[options]",
      description: "Custom command.",
      options: [
        {
          name: "output",
          alias: "o",
          configs: [
            {
              type: "string",
            },
          ],
          description: "To get the output in a specified format",
          hidden: false,
        },
      ],
      action: async (options) => {
        cli.logger.raw(`custom ${options.output ? options.output : "unknown"}`);
      },
    });

    return customCommand;
  }
}
